from flask import Flask
import yaml
from yaml.representer import SafeRepresenter

app = Flask(__name__)

class Song:
    def __init__(self, title, album):
        self.title = title
        self.album = album

def song_representer(dumper, data):
    return dumper.represent_dict({
        'title': data.title,
        'album': data.album
    })

SafeRepresenter.add_representer(Song, song_representer)

